#!/usr/bin/env python3 """HermesData entrypoint delegates to ~/.hermes/scripts/universal_ingest_monitor.py.""" from __future__ import annotations import runpy import sys from pathlib import Path _CANONICAL = Path(r"D:\HermesData\.hermes\scripts\universal_ingest_monitor.py") if __name__ == "__main__": if not _CANONICAL.is_file(): print(f"Canonical monitor missing: {_CANONICAL}", file=sys.stderr) raise SystemExit(2) sys.argv[0] = str(_CANONICAL) runpy.run_path(str(_CANONICAL), run_name="__main__")